#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    // 1. Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = conn_result.value();

    // 2. Drop the table if it exists
    auto drop_result = (sqlgen::drop<Product> | sqlgen::if_exists)(conn);
    if (!drop_result) {
        return false;
    }

    // 3. Begin a transaction
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    // 4. Insert the products using batch operation
    auto products_range = products.begin(), products_end = products.end();
    auto insert_result = sqlgen::insert(conn, products_range, products_end);
    if (!insert_result) {
        // Transaction will automatically roll back if insert fails
        return false;
    }

    // 5. Commit the transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
        return false;
    }

    return true;
}

}  // namespace batch_insert_products
```

## Key Implementation Points:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish connection
2. **Table Management**: Drops table using `sqlgen::drop<Product> | sqlgen::if_exists` pattern
3. **Transaction Handling**: Begins transaction with `begin_transaction()` and commits with `commit()`
4. **Batch Insertion**: Uses `sqlgen::insert()` with the products range for efficient batch operation
5. **Error Handling**: Checks results of each operation and returns `false` on failure
6. **Resource Management**: Properly handles connection and transaction lifecycle

The implementation follows the exact sequence specified in the assessment objectives and leverages the sqlgen library's fluent interface for database operations.

