  };

  if (!create_tables(conn)) {
    throw std::runtime_error("Failed to create tables");
  }

  // 3. Construct the complex query using sqlgen's fluent interface
  using namespace sqlgen::literals;

  auto query = sqlgen::select_from<Product>("name"_c)
    | sqlgen::join<Order, "order">(sqlgen::on("product_id"_c == "product_id"_c))
    | sqlgen::join<OrderItem, "order_item">(sqlgen::on("order_id"_c == "order_id"_c))
    | sqlgen::join<Customer, "customer">(sqlgen::on("customer_id"_c == "customer_id"_c))
    | sqlgen::where("customer.customer_id"_c == customer_id)
