    auto result = sqlgen::create_table<Customer>(conn);
    if (!result) return false;

    result = sqlgen::create_table<Order>(conn);
    if (!result) return false;

    result = sqlgen::create_table<OrderItem>(conn);
    if (!result) return false;

    result = sqlgen::create_table<Product>(conn);
    return result;
  };

  if (!create_tables(conn)) {
    throw std::runtime_error("Failed to create tables");
  }

  // 3. Construct the complex query using sqlgen's fluent interface
  using namespace sqlgen::literals;

  auto query = sqlgen::select_from<Product>("name"_c)
    | sqlgen::join<Order, "order">(sqlgen::on("product_id"_c == "product_id"_c))
    | sqlgen::join<OrderItem, "order_item">(sqlgen::on("order_id"_c == "order_id"_c))
    | sqlgen::join<Customer, "customer">(sqlgen::on("customer_id"_c == "customer_id"_c))
    | sqlgen::where("customer.customer_id"_c == customer_id)
    | sqlgen::order_by("order.order_date"_c.desc());

  // 4. Execute the query and read results
  auto result = query(conn);
  if (!result) {
    throw std::runtime_error("Query failed");
  }

  // 5. Map the results to PurchaseHistory objects
  auto purchase_history = sqlgen::read<std::vector<PurchaseHistory>>(result.value());
  if (!purchase_history) {
    throw std::runtime_error("Failed to read results");
  }

  return purchase_history.value();
}

}  // namespace query_customer_purchase_history

