#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // 2. Construct the base SELECT query
    auto query = sqlgen::select_from<Book>();

    // 3. Dynamically add WHERE conditions based on filters
    if (filters.title_keyword.has_value()) {
        query = query.where("title"_c.like("%" + filters.title_keyword.value() + "%"));
    }

    if (filters.min_year.has_value()) {
        if (query.where_condition) {
            query.where_condition = query.where_condition && ("year"_c >= filters.min_year.value());
        } else {
            query = query.where("year"_c >= filters.min_year.value());
        }
    }

    if (filters.genre.has_value()) {
        if (query.where_condition) {
            query.where_condition = query.where_condition && ("genre"_c == filters.genre.value());
        } else {
            query = query.where("genre"_c == filters.genre.value());
        }
    }

    if (filters.max_price.has_value()) {
        if (query.where_condition) {
            query.where_condition = query.where_condition && ("price"_c <= filters.max_price.value());
        } else {
            query = query.where("price"_c <= filters.max_price.value());
        }
    }

    // 4. Execute the query and return results
    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Query failed");
    }

    return result.value();
}

}  // namespace query_search_books_by_criteria
```

