namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::string city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
  sqlgen::PrimaryKey<std::pair<int, int>> primary_key;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect();

  // Create tables for User and Friendship
  auto user_table = sqlgen::create_table<User>;
  auto friendship_table = sqlgen::create_table<Friendship>;

  // Insert sample data
  auto insert_users = sqlgen::insert(users.begin(), users.end());
  auto insert_friendships = sqlgen::insert(friendships.begin(), friendships.end());

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends_query = sqlgen::select_from<User>(
      "username"_c,
      "username"_c | sqlgen::as<"user2_name">
  ) | sqlgen::inner_join<Friendship>("user_id"_c == "user1_id"_c) | sqlgen::inner_join<User>(
      "user2_id"_c == "user_id"_c
  ) | sqlgen::where("user_id"_c < "user_id"_c) | sqlgen::group_by("user_id"_c, "user_id"_c);

  // Query 2: Users with more than N friends using nested query
  auto popular_users_query = sqlgen::select_from<User>(
      "username"_c,
      sqlgen::count("user1_id"_c) | sqlgen::as<"friend_count">
  ) | sqlgen::left_join<Friendship>("user_id"_c == "user1_id"_c) | sqlgen::group_by("user_id"_c);

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = sqlgen::select_from<User>(
      "username"_c | sqlgen::as<"user1_name">
  ) | sqlgen::inner_join<Friendship>("user_id"_c == "user1_id"_c) | sqlgen::inner_join<User>(
      "user2_id"_c == "user_id"_c
  ) | sqlgen::where(sqlgen::not_exists(sqlgen::select_from<Friendship>("user1_id"_c == "user2_id"_c)));

  // Execute queries and process results
  auto mutual_results = mutual_friends_query(conn);
  auto popular_results = popular_users_query(conn);
  auto friend_of_friend_results = friend_of_friend_query(conn);

  // Convert results to FriendConnection vector
  std::vector<FriendConnection> connections;

  // Process mutual friends results
  for (const auto& row : mutual_results) {
    connections.push_back(FriendConnection{
        .user1_name = row["username"].get<std::string>(),
        .user2_name = row["user2_name"].get<std::string()}
    );
  }

  // Process friend-of-friend results
  for (const auto& row : friend_of_friend_results) {
    connections.push_back(FriendConnection{
        .user1_name = row["user1_name"].get<std::string()},
        .user2_name = "Friend-of-Friend"
    });
  }

  return std::move(connections);
}

}  // namespace analyze_social_network
```

