 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect();
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create temporary tables for departments and employees
  auto dept_table = sqlgen::create_table<Department>;
  auto emp_table = sqlgen::create_table<Employee>;

  // Insert department data
  auto dept_insert = sqlgen::insert(conn, depts);
  if (!dept_insert) {
    throw std::runtime_error("Failed to insert department data");
  }

  // Insert employee data
  auto emp_insert = sqlgen::insert(conn, emps);
  if (!emp_insert) {
    throw std::runtime_error("Failed to insert employee data");
  }

  // Define column references using table aliases
  using namespace sqlgen::literals;
  auto d = "d"_t1;  // Department table alias
  auto e = "e"_t2;  // Employee table alias

  // Build INNER JOIN query
  auto inner_join_query = sqlgen::select_from<Department, "d">(d["department_name"], 
                                                              e["first_name"], 
                                                              e["last_name"], 
                                                              e["salary"])
                       | sqlgen::inner_join<Employee, "e">(d["department_id"] == e["department_id"])
                       | sqlgen::to<std::vector<JoinResult>>;

  // Build LEFT JOIN query
  auto left_join_query = sqlgen::select_from<Employee, "e">(e["department_id"], 
                                                          d["department_name"], 
                                                          e["first_name"], 
                                                          e["last_name"], 
                                                          e["salary"])
                      | sqlgen::left_join<Department, "d">(e["department_id"] == d["department_id"])
                      | sqlgen::to<std::vector<JoinResult>>;

  // Build RIGHT JOIN query  
