#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace delete_with_complex_condition {

struct User {
  sqlgen::PrimaryKey<int> id;
  int age;
  std::string status;
};

/**
 * This function demonstrates deleting with complex conditions.
 * Returns: std::string.
 */
inline std::string delete_with_complex_condition() {
    using namespace sqlgen::literals;

    // Create column references using literal operator
    auto age_col = "age"_c;
    auto status_col = "status"_c;

    // Build complex condition: age < 18 OR status = 'inactive'
    auto condition = (age_col < 18) || (status_col == "inactive");

    // Construct DELETE statement with WHERE clause
    auto delete_stmt = sqlgen::delete_from<User> | sqlgen::where(condition);

    // Convert to SQL string and return
    return sqlgen::sqlite::to_sql(delete_stmt);
}

}  // namespace delete_with_complex_condition
```

## Explanation of Implementation:

1. **Column References**: Used the literal operator `""_c` from `sqlgen::literals` namespace to create column references for "age" and "status".

2. **Complex Condition**: Built the condition using:
   - `age_col < 18` for age less than 18
   - `status_col == "inactive"` for status equal to "inactive"
   - Combined with `||` (OR operator) as specified

3. **DELETE Statement Construction**: 
   - Used `sqlgen::delete_from<User>` to start building the DELETE statement
   - Applied the WHERE clause using the `|` operator with `sqlgen::where(condition)`

4. **SQL Generation**: Converted the final statement to SQL string using `sqlgen::sqlite::to_sql()`

The generated SQL would be similar to:
```sql
DELETE FROM User WHERE (age < 18) OR (status = 'inactive')
```

This implementation follows all the specified requirements and uses the sqlgen library components as documented in the reference materials.

