```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create SELECT query from Source with WHERE condition
    auto select_query = sqlgen::select_from<Source>("value"_c)
                        | sqlgen::where("value"_c > 100);

    // Create table creation statement from SELECT query
    auto create_stmt = sqlgen::create_as<Target>(select_query)
                      | sqlgen::if_not_exists;

    return create_stmt;
}

}  // namespace create_table_as_select
```

## Explanation:

1. **SELECT Query Construction**: 
   - `sqlgen::select_from<Source>("value"_c)` creates a SELECT query targeting the `Source` table, selecting only the `value` column using the string literal operator `_c`.

2. **WHERE Condition**:
   - `| sqlgen::where("value"_c > 100)` applies the filter condition `value > 100` using the pipe operator to chain operations.

3. **Table Creation**:
   - `sqlgen::create_as<Target>(select_query)` creates a CREATE TABLE AS SELECT statement for the `Target` table using the previously constructed SELECT query.

4. **IF NOT EXISTS Clause**:
   - `| sqlgen::if_not_exists` adds the IF NOT EXISTS clause to prevent errors if the table already exists.

The function returns the final query object that can be executed against a database connection to create the `Target` table with the filtered data from the `Source` table.

